import React, { useEffect, useState, useCallback, useRef } from 'react';
import api from '../api/axiosConfig';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, Sun, Moon } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedItem, setSelectedItem] = useState(null);
  const [isDark, setIsDark] = useState(true); // default dark – change to false for light default
  const modalRef = useRef(null);

  const toggleTheme = () => {
    setIsDark((prev) => !prev);
    // Later: save to localStorage or sync with system preference
  };

  const safeParseHoldings = useCallback((data) => {
    if (!data) return [];
    try {
      let parsed = typeof data === 'string' ? JSON.parse(data) : data;
      if (typeof parsed === 'string') parsed = JSON.parse(parsed);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      console.error('Holdings parse failed:', e);
      return [];
    }
  }, []);

  const fetchHistory = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await api.get('/portfolio/history');
      setHistory(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      console.error('Fetch history failed:', err);
      const msg = err.response?.data?.message || 'Could not load vault data';
      setError(msg);
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  }, []);

  const handleDelete = useCallback(async (id) => {
    if (!window.confirm('This action cannot be undone.\nDelete strategy permanently?')) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory((prev) => prev.filter((item) => item?.id !== id));
      toast.success('Strategy deleted');
      if (selectedItem?.id === id) setSelectedItem(null);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Delete failed');
    }
  }, [selectedItem]);

  const handleDownload = useCallback(async (item) => {
    if (!item?.id) return toast.error('Invalid strategy');
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Strategy_${item.id}_${new Date().toISOString().split('T')[0]}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.URL.revokeObjectURL(url);
      toast.success('Download started');
    } catch (err) {
      toast.error('Could not generate PDF');
    }
  }, []);

  useEffect(() => {
    const handleEsc = (e) => {
      if (e.key === 'Escape') setSelectedItem(null);
    };
    if (selectedItem) {
      window.addEventListener('keydown', handleEsc);
      return () => window.removeEventListener('keydown', handleEsc);
    }
  }, [selectedItem]);

  useEffect(() => {
    fetchHistory();
  }, [fetchHistory]);

  useEffect(() => {
    if (selectedItem && modalRef.current) {
      modalRef.current.focus();
    }
  }, [selectedItem]);

  if (loading) return <div style={centerStyle}>Loading vault…</div>;

  if (error) {
    return (
      <div style={centerStyle}>
        <div style={{ color: 'var(--danger)', marginBottom: '1rem' }}>Error</div>
        <div>{error}</div>
        <button
          onClick={fetchHistory}
          style={{
            marginTop: '1.5rem',
            padding: '0.6rem 1.2rem',
            background: 'var(--accent)',
            color: 'var(--text-inverted)',
            border: 'none',
            borderRadius: '8px',
            cursor: 'pointer',
          }}
        >
          Retry
        </button>
      </div>
    );
  }

  return (
    <div style={{ ...containerStyle, background: 'var(--bg-primary)' }}>
      <div style={headerRow}>
        <h2 style={headerStyle}>
          <Archive size={20} color="var(--accent)" aria-hidden="true" /> Strategy Vault
        </h2>

        <div style={{ display: 'flex', alignItems: 'center', gap: '1.2rem' }}>
          <span style={nodeCount}>
            {history.length} {history.length === 1 ? 'strategy' : 'strategies'}
          </span>
          <button
            type="button"
            onClick={toggleTheme}
            style={{
              background: 'none',
              border: 'none',
              cursor: 'pointer',
              color: 'var(--text-secondary)',
              padding: '6px',
              borderRadius: '8px',
            }}
            aria-label={isDark ? 'Switch to light mode' : 'Switch to dark mode'}
          >
            {isDark ? <Sun size={20} /> : <Moon size={20} />}
          </button>
        </div>
      </div>

      {history.length === 0 ? (
        <div style={emptyStyle}>
          <p>No saved strategies yet.</p>
          <p style={{ fontSize: '0.9rem', marginTop: '0.8rem', opacity: 0.7 }}>
            Create a new strategy to see it appear here.
          </p>
        </div>
      ) : (
        <div style={listStyle}>
          {history.map((item) => (
            <div key={item.id} style={cardStyle}>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={tagRow}>
                  <span style={dateTag}>
                    <Calendar size={12} aria-hidden="true" />
                    {item.created_at
                      ? new Date(item.created_at).toLocaleDateString('en-GB')
                      : '—'}
                  </span>
                  <span style={riskTag}>
                    <ShieldCheck size={12} aria-hidden="true" />
                    Risk: {item.risk_score ?? '—'}
                  </span>
                </div>

                <h4 style={titleStyle}>{item.goal || 'Unnamed Strategy'}</h4>

                <div style={tickerRow}>
                  {safeParseHoldings(item.holdings).map((ticker, idx) => (
                    <span key={idx} style={tickerTag}>
                      {ticker}
                    </span>
                  ))}
                  {safeParseHoldings(item.holdings).length === 0 && (
                    <span style={{ ...tickerTag, opacity: 0.6 }}>No holdings</span>
                  )}
                </div>
              </div>

              <div style={actionRow}>
                <button
                  type="button"
                  onClick={() => setSelectedItem(item)}
                  style={iconBtn}
                  title="View details"
                  aria-label={`View details of strategy ${item.id}`}
                >
                  <Eye size={18} />
                </button>
                <button
                  type="button"
                  onClick={() => handleDownload(item)}
                  style={iconBtn}
                  title="Download PDF"
                  aria-label={`Download PDF for strategy ${item.id}`}
                >
                  <Download size={18} />
                </button>
                <button
                  type="button"
                  onClick={() => handleDelete(item.id)}
                  style={deleteBtn}
                  title="Delete strategy"
                  aria-label={`Delete strategy ${item.id}`}
                >
                  <Trash2 size={18} />
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {selectedItem && (
        <div
          style={modalOverlay}
          onClick={() => setSelectedItem(null)}
          role="dialog"
          aria-modal="true"
          aria-labelledby="strategy-modal-title"
        >
          <div
            ref={modalRef}
            style={modalContent}
            onClick={(e) => e.stopPropagation()}
            tabIndex={-1}
          >
            <div style={modalHeader}>
              <h3 id="strategy-modal-title" style={modalTitle}>
                Strategy #{selectedItem.id}
              </h3>
              <button
                type="button"
                onClick={() => setSelectedItem(null)}
                style={closeBtn}
                aria-label="Close preview"
              >
                <X size={22} />
              </button>
            </div>

            <div style={modalBody}>
              <section style={section}>
                <h4 style={sectionLabel}>Summary</h4>
                <div style={sectionContent}>
                  {selectedItem.summary?.trim() || 'No summary available.'}
                </div>
              </section>

              <section style={section}>
                <h4 style={sectionLabel}>Rationale</h4>
                <div style={sectionContent}>
                  {selectedItem.rationale?.trim() || 'No rationale provided.'}
                </div>
              </section>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

/* ────────────────────────────────────────────────
   Light + Dark mode variables + base styles
───────────────────────────────────────────────── */

const baseContainer = {
  padding: '2rem 1.25rem',
  maxWidth: '1140px',
  margin: '0 auto',
  minHeight: '80vh',
  transition: 'background 0.25s ease, color 0.25s ease',
};

const containerStyle = baseContainer; // will inherit bg from :root / .dark

// ── You should put this in a global stylesheet (index.css / App.css) ──
/*

:root {
  color-scheme: light dark;
  --bg-primary:        #ffffff;
  --bg-secondary:      #f8f9fa;
  --bg-glass:          rgba(255, 255, 255, 0.75);
  --bg-modal:          #ffffff;
  --bg-header:         #f1f3f5;
  --bg-hover:          rgba(0, 0, 0, 0.06);

  --text-strong:       #0f172a;
  --text-readable:     #1e293b;
  --text-primary:      #334155;
  --text-secondary:    #64748b;
  --text-muted:        #94a3b8;
  --text-inverted:     #ffffff;

  --accent:            #10b981;
  --accent-dimmed:     #059669;
  --accent-very-dim:   rgba(16, 185, 129, 0.12);
  --accent-glow:       rgba(16, 185, 129, 0.18);

  --border-visible:    rgba(203, 213, 225, 0.6);
  --border-accent:     rgba(16, 185, 129, 0.35);

  --danger:            #ef4444;
  --danger-bright:     #f87171;
}

.dark {
  --bg-primary:        #0f172a;
  --bg-secondary:      #1e293b;
  --bg-glass:          rgba(15, 23, 42, 0.66);
  --bg-modal:          #0f172a;
  --bg-header:         rgba(15, 23, 42, 0.84);
  --bg-hover:          rgba(30, 41, 59, 0.58);

  --text-strong:       #f8fafc;
  --text-readable:     #e5e7eb;
  --text-primary:      #cbd5e1;
  --text-secondary:    #94a3b8;
  --text-muted:        #64748b;
  --text-inverted:     #0f172a;

  --accent:            #34d399;
  --accent-dimmed:     #10b981;
  --accent-very-dim:   rgba(52, 211, 153, 0.14);
  --accent-glow:       rgba(52, 211, 153, 0.26);

  --border-visible:    rgba(120, 140, 180, 0.28);
  --border-accent:     rgba(52, 211, 153, 0.28);
}

*/

/* Component styles – use variables everywhere */

const headerRow = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  marginBottom: '2.25rem',
  paddingBottom: '1rem',
  borderBottom: '1px solid var(--border-visible)',
};

const headerStyle = {
  color: 'var(--text-strong)',
  display: 'flex',
  alignItems: 'center',
  gap: '10px',
  fontSize: '1.28rem',
  fontWeight: 600,
  margin: 0,
};

const nodeCount = {
  fontSize: '0.82rem',
  color: 'var(--text-muted)',
  fontFamily: 'ui-monospace, monospace',
};

const listStyle = { display: 'flex', flexDirection: 'column', gap: '1.1rem' };

const cardStyle = {
  display: 'flex',
  padding: '1.4rem 1.6rem',
  background: 'var(--bg-glass)',
  border: '1px solid var(--border-visible)',
  borderRadius: '14px',
  gap: '1.5rem',
  transition: 'all 0.18s ease',
};

const tagRow = { display: 'flex', gap: '1rem', marginBottom: '0.8rem', flexWrap: 'wrap' };

const dateTag = {
  fontSize: 'clamp(0.74rem, 3.3vw, 0.81rem)',
  color: 'var(--text-muted)',
  display: 'flex',
  alignItems: 'center',
  gap: '5px',
};

const riskTag = {
  fontSize: 'clamp(0.74rem, 3.3vw, 0.81rem)',
  color: 'var(--accent-dimmed)',
  fontWeight: 500,
  display: 'flex',
  alignItems: 'center',
  gap: '5px',
};

const titleStyle = {
  margin: '0 0 1rem',
  color: 'var(--text-strong)',
  fontSize: '1.1rem',
  fontWeight: 600,
  lineHeight: 1.38,
};

const tickerRow = { display: 'flex', flexWrap: 'wrap', gap: '6px' };

const tickerTag = {
  fontSize: 'clamp(0.72rem, 3.1vw, 0.79rem)',
  padding: '4px 10px',
  background: 'var(--accent-very-dim)',
  border: '1px solid var(--accent-dimmed)',
  borderRadius: '6px',
  color: 'var(--accent-dimmed)',
  fontFamily: 'ui-monospace, monospace',
  fontWeight: 500,
};

const actionRow = {
  display: 'flex',
  flexDirection: 'column',
  gap: '0.75rem',
  paddingLeft: '1.4rem',
  borderLeft: '1px solid var(--border-visible)',
  justifyContent: 'center',
};

const iconBtn = {
  background: 'none',
  border: 'none',
  color: 'var(--text-secondary)',
  cursor: 'pointer',
  padding: '6px',
  borderRadius: '8px',
  transition: 'all 0.16s ease',
};

const deleteBtn = {
  ...iconBtn,
  color: 'var(--danger)',
};

const centerStyle = {
  minHeight: '60vh',
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  color: 'var(--text-secondary)',
  fontSize: '0.98rem',
  textAlign: 'center',
};

const emptyStyle = {
  textAlign: 'center',
  color: 'var(--text-muted)',
  padding: '6.5rem 2rem',
  border: '1px dashed var(--border-visible)',
  borderRadius: '16px',
  background: 'var(--bg-secondary)',
  fontSize: '0.97rem',
};

/* Modal styles */

const modalOverlay = {
  position: 'fixed',
  inset: 0,
  background: 'rgba(0,0,0,0.7)',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  zIndex: 1000,
  backdropFilter: 'blur(8px)',
};

const modalContent = {
  width: 'min(94%, 760px)',
  background: 'var(--bg-modal)',
  border: '1px solid var(--border-visible)',
  borderRadius: '16px',
  overflow: 'hidden',
  boxShadow: '0 24px 64px rgba(0,0,0,0.3)',
  outline: 'none',
};

const modalHeader = {
  padding: '1.1rem 1.6rem',
  background: 'var(--bg-header)',
  borderBottom: '1px solid var(--border-visible)',
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
};

const modalTitle = {
  margin: 0,
  fontSize: '1.05rem',
  fontWeight: 600,
  color: 'var(--text-strong)',
};

const modalBody = {
  padding: '2rem 2.2rem',
  maxHeight: '74vh',
  overflowY: 'auto',
};

const section = { marginBottom: '2.4rem' };

const sectionLabel = {
  color: 'var(--accent-dimmed)',
  fontSize: '0.82rem',
  fontWeight: 700,
  letterSpacing: '0.04em',
  marginBottom: '1rem',
  textTransform: 'uppercase',
};

const sectionContent = {
  fontSize: '0.96rem',
  lineHeight: 1.86,
  color: 'var(--text-readable)',
  whiteSpace: 'pre-wrap',
  wordBreak: 'break-word',
};

const closeBtn = {
  background: 'none',
  border: 'none',
  color: 'var(--text-secondary)',
  cursor: 'pointer',
  padding: '6px',
  borderRadius: '8px',
  transition: 'all 0.16s',
};

export default VaultPage;
